'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes, ReactNode } from 'react'
import { AutoGrid } from '../../auto-grid/auto-grid'
import styles from './page-footer.module.css'

export interface FooterLink {
  label: ReactNode
  href: string
}

export interface FooterGroup {
  title: ReactNode
  links: FooterLink[]
}

export interface PageFooterProps extends HTMLAttributes<HTMLElement> {
  groups: FooterGroup[]
  brand?: ReactNode
  meta?: ReactNode
  className?: string | undefined
}

export function PageFooter({ groups, brand, meta, className, ...props }: PageFooterProps) {
  return (
    <footer className={cn(styles['page-footer'], className)} {...props}>
      <div className={styles['inner']}>
        <nav aria-label="Footer">
          <AutoGrid min="10rem" gap={6}>
            {groups.map((group, i) => (
              <div key={i} className={styles['group']}>
                <p className={styles['group-title']}>{group.title}</p>
                <ul className={styles['link-list']}>
                  {group.links.map((link, j) => (
                    <li key={j}>
                      <a href={link.href} className={styles['link']}>
                        {link.label}
                      </a>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </AutoGrid>
        </nav>
        {(brand || meta) && (
          <div className={styles['bottom']}>
            {brand && <div className={styles['brand']}>{brand}</div>}
            {meta && <div className={styles['meta']}>{meta}</div>}
          </div>
        )}
      </div>
    </footer>
  )
}

@layer cascivo.component {
  .page-footer {
    padding-block: var(--cascivo-space-10);
    padding-inline: var(--cascivo-space-4);
    border-block-start: 1px solid var(--cascivo-color-border);
  }

  .inner {
    max-inline-size: 72rem;
    margin-inline: auto;
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-8);
  }

  .group {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-3);
    min-inline-size: 0;
  }

  .group-title {
    font-size: var(--cascivo-text-sm);
    font-family: var(--cascivo-font-mono);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-text-secondary);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin: 0;
  }

  .link-list {
    list-style: none;
    padding: 0;
    margin: 0;
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
  }

  .link {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-text-primary);
    text-decoration: none;
  }

  .link:hover {
    color: var(--cascivo-color-accent);
  }

  .bottom {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: var(--cascivo-space-4);
    padding-block-start: var(--cascivo-space-6);
    border-block-start: 1px solid var(--cascivo-color-border);
  }

  .brand {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-semibold);
  }

  .meta {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-text-secondary);
  }
}
